use axum::{
    extract::State,
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::post,
    Json, Router,
};
use serde::{Deserialize, Serialize};

fn routes(state: AppState) -> Router {
    Router::new()
        .route("/resources", post(endpoint_handler))
        .with_state(state)
}

#[derive(Debug, Deserialize)]
struct EndpointRequest {
    value: String,
}

#[derive(Debug, Serialize)]
struct EndpointResponse {
    id: String,
}

async fn endpoint_handler(
    State(state): State<AppState>,
    Json(request): Json<EndpointRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let input = UseCaseInput::from(request);
    let output = state.use_cases.target_use_case.execute(input).await?;

    Ok((StatusCode::CREATED, Json(EndpointResponse::from(output))))
}

struct ApiError(AppError);

impl From<AppError> for ApiError {
    fn from(error: AppError) -> Self {
        Self(error)
    }
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        let (status, code) = match self.0 {
            AppError::InvalidInput => (StatusCode::BAD_REQUEST, "invalid_input"),
            AppError::NotFound => (StatusCode::NOT_FOUND, "not_found"),
            AppError::Conflict => (StatusCode::CONFLICT, "conflict"),
        };

        (status, Json(ErrorResponse { code })).into_response()
    }
}

#[derive(Debug, Serialize)]
struct ErrorResponse {
    code: &'static str,
}
